func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const alpha = 0.7
	const beta = 0.3
	for shipIdx := 0; shipIdx < len(oris); shipIdx++ {
		ori := oris[shipIdx]
		des := dess[shipIdx]
		shipID := total_ship + shipIdx
		bestScore := math.MaxFloat64
		bestAssignIdx := -1
		originalCosts := make([]float64, dispatch.AssignsLen)
		for i := 0; i < dispatch.AssignsLen; i++ {
			originalCosts[i] = dispatch.Assigns[i].Cost
		}
		for tryAssignIdx := 0; tryAssignIdx <= dispatch.AssignsLen; tryAssignIdx++ {
			var savedCost float64
			var oldStationsLen int
			success := false
			score := 0.0
			if tryAssignIdx < dispatch.AssignsLen {
				assignPtr := &dispatch.Assigns[tryAssignIdx]
				savedCost = assignPtr.Cost
				if assignPtr.AddShip(shipID, ori, des) {
					assignPtr.GenRoute()
					if assignPtr.Cost >= 0 {
						delta := assignPtr.Cost - savedCost
						timePen := 0.0
						if ori.TimeStart > 0 && ori.TimeEnd > ori.TimeStart {
							window := float64(ori.TimeEnd - ori.TimeStart)
							if window > 0 {
								timePen = beta / window
							}
						}
						score = alpha*delta + timePen
						success = true
					}
					assignPtr.RemoveShip(shipID)
					assignPtr.GenRoute()
				}
				assignPtr.Cost = savedCost
			} else {
				if tryAssignIdx < MAXASSIGNS {
					assignPtr := &dispatch.Assigns[tryAssignIdx]
					oldStationsLen = assignPtr.StationsLen
					oldCost := assignPtr.Cost
					savedCost = oldCost
					if assignPtr.AddShip(shipID, ori, des) {
						assignPtr.GenRoute()
						if assignPtr.Cost >= 0 {
							delta := assignPtr.Cost - savedCost
							score = alpha * delta
							success = true
						}
						assignPtr.RemoveShip(shipID)
						assignPtr.StationsLen = oldStationsLen
						assignPtr.Cost = oldCost
						assignPtr.GenRoute()
					}
				}
			}
			if success && score < bestScore {
				bestScore = score
				bestAssignIdx = tryAssignIdx
			}
		}
		for i := 0; i < dispatch.AssignsLen; i++ {
			dispatch.Assigns[i].Cost = originalCosts[i]
		}
		inserted := false
		if bestAssignIdx >= 0 && bestAssignIdx < dispatch.AssignsLen {
			if dispatch.Assigns[bestAssignIdx].AddShip(shipID, ori, des) {
				dispatch.Assigns[bestAssignIdx].GenRoute()
				inserted = true
			}
		}
		if !inserted && bestAssignIdx == dispatch.AssignsLen && dispatch.AssignsLen < MAXASSIGNS {
			newIdx := dispatch.AssignsLen
			tmp := &dispatch.Assigns[newIdx]
			if tmp.AddShip(shipID, ori, des) {
				tmp.GenRoute()
				if tmp.Cost >= 0 {
					dispatch.AssignsLen++
					inserted = true
				} else {
					tmp.RemoveShip(shipID)
					tmp.GenRoute()
				}
			}
		}
		if !inserted {
			for tryNewIdx := dispatch.AssignsLen; tryNewIdx < MAXASSIGNS; tryNewIdx++ {
